// Same signature as identity::TEST_SIGNATURE
global TEST_SIGNATURE: [u8; 64] = [
    0xac, 0x7c, 0x16, 0x38, 0x2d, 0x05, 0xd1, 0xd5,
    0x7f, 0xb3, 0x46, 0x34, 0xb3, 0x69, 0x9c, 0x41,
    0x06, 0xf9, 0x6d, 0x71, 0x13, 0x2e, 0x52, 0x09,
    0x9d, 0x79, 0x2a, 0x97, 0xc5, 0xb8, 0x82, 0xe8,
    0x09, 0x25, 0xb4, 0x15, 0xae, 0x8d, 0x91, 0x94,
    0x10, 0x99, 0x54, 0xee, 0xfd, 0xb9, 0x9f, 0xd1,
    0xfe, 0x4e, 0x4c, 0x52, 0xd6, 0xf0, 0x79, 0x9b,
    0x01, 0xae, 0x26, 0xd0, 0x40, 0x76, 0x4d, 0x5d,
];

#[test]
fn test_bytes32_to_field_zero() {
    let zero = [0u8; 32];
    assert(bytes32_to_field(zero) == 0);
}

#[test]
fn test_bytes32_to_field_one() {
    let mut one = [0u8; 32];
    one[31] = 1;
    assert(bytes32_to_field(one) == 1);
}

#[test]
fn test_bytes32_to_field_known_value() {
    let mut bytes = [0u8; 32];
    bytes[31] = 0xff;
    assert(bytes32_to_field(bytes) == 255);
}

#[test]
fn test_bytes32_to_field_multi_byte() {
    // 0x0100 = 256
    let mut bytes = [0u8; 32];
    bytes[30] = 1;
    assert(bytes32_to_field(bytes) == 256);

    // 0x0101 = 257
    bytes[31] = 1;
    assert(bytes32_to_field(bytes) == 257);
}

#[test]
fn test_bytes32_to_field_real_signature_r() {
    // r from TEST_SIGNATURE: first 32 bytes
    let r: [u8; 32] = [
        0xac, 0x7c, 0x16, 0x38, 0x2d, 0x05, 0xd1, 0xd5,
        0x7f, 0xb3, 0x46, 0x34, 0xb3, 0x69, 0x9c, 0x41,
        0x06, 0xf9, 0x6d, 0x71, 0x13, 0x2e, 0x52, 0x09,
        0x9d, 0x79, 0x2a, 0x97, 0xc5, 0xb8, 0x82, 0xe8,
    ];
    let r_field = bytes32_to_field(r);
    // Should be non-zero and produce a valid Field
    assert(r_field != 0);
}

#[test]
fn test_nullifier_deterministic() {
    // Same signature + same balance = same nullifier
    let balance: Field = 1000000000000000000; // 1 ETH in wei

    let n1 = compute_nullifier(TEST_SIGNATURE, balance);
    let n2 = compute_nullifier(TEST_SIGNATURE, balance);
    assert(n1 == n2);
}

#[test]
fn test_different_balance_different_nullifier() {
    // Same signature, different balance = different nullifier
    let balance_1eth: Field = 1000000000000000000;
    let balance_10eth: Field = 10000000000000000000;

    let n1 = compute_nullifier(TEST_SIGNATURE, balance_1eth);
    let n2 = compute_nullifier(TEST_SIGNATURE, balance_10eth);
    assert(n1 != n2);
}

#[test]
fn test_different_signature_different_nullifier() {
    // Different signature, same balance = different nullifier
    let mut other_sig = TEST_SIGNATURE;
    other_sig[0] = 0xff;

    let balance: Field = 1000000000000000000;
    let n1 = compute_nullifier(TEST_SIGNATURE, balance);
    let n2 = compute_nullifier(other_sig, balance);
    assert(n1 != n2);
}

#[test]
fn test_nullifier_nonzero() {
    // Nullifier from real data should not be the zero element
    let balance: Field = 1000000000000000000;
    let n = compute_nullifier(TEST_SIGNATURE, balance);
    assert(n != 0);
}

57.source:
mod tests;
mod oracle_tests;
mod benchmarks;

use std::hash::keccakf1600;
use std::runtime::is_unconstrained;

global BLOCK_SIZE_IN_BYTES: u32 = 136; //(1600 - BITS * 2) / WORD_SIZE;
global WORD_SIZE: u32 = 8; // Limbs are made up of u64s so 8 bytes each.
global LIMBS_PER_BLOCK: u32 = BLOCK_SIZE_IN_BYTES / WORD_SIZE;
global NUM_KECCAK_LANES: u32 = 25;

#[no_predicates]
pub fn keccak256<let N: u32>(input: [u8; N], message_size: u32) -> [u8; 32] {
    assert(N >= message_size);

    // Copy input to block bytes. For that we'll need at least input bytes (N)
    // but we want it to be padded to a multiple of BLOCK_SIZE_IN_BYTES.
    let mut block_bytes = [0; ((N / BLOCK_SIZE_IN_BYTES) + 1) * BLOCK_SIZE_IN_BYTES];
    if is_unconstrained() {
        for i in 0..message_size {
            block_bytes[i] = input[i];
        }
    } else {
        for i in 0..N {
            if i < message_size {
                block_bytes[i] = input[i];
            }
        }
    }

    //1. format_input_lanes and apply padding
    let max_blocks = (N + BLOCK_SIZE_IN_BYTES) / BLOCK_SIZE_IN_BYTES;
    let real_max_blocks = (message_size + BLOCK_SIZE_IN_BYTES) / BLOCK_SIZE_IN_BYTES;

    // Apply Keccak padding (0x01 after message, 0x80 at block end)
    apply_keccak_padding(&mut block_bytes, message_size, real_max_blocks);

    // populate a vector of 64-bit limbs from our byte array
    let mut sliced_buffer =
        [0; (((N / BLOCK_SIZE_IN_BYTES) + 1) * BLOCK_SIZE_IN_BYTES) / WORD_SIZE];
    for i in 0..sliced_buffer.len() {
        let limb_start = WORD_SIZE * i;

        let mut sliced = 0;
        let mut v = 1;
        for k in 0..WORD_SIZE {
            sliced += v * (block_bytes[limb_start + k] as Field);
            v *= 256;
        }

        sliced_buffer[i] = sliced as u64;
    }

    //2. sponge_absorb
    let mut state: [u64; NUM_KECCAK_LANES] = [0; NUM_KECCAK_LANES];
    // `real_max_blocks` is guaranteed to at least be `1`
    // We peel out the first block as to avoid a conditional inside of the loop.
    // Otherwise, a dynamic predicate can cause a blowup in a constrained runtime.
    for j in 0..LIMBS_PER_BLOCK {
        state[j] = sliced_buffer[j];
    }
    state = keccakf1600(state);

    let state = if is_unconstrained() {
        // When in an unconstrained runtime we can take advantage of runtime loop bounds,
        // thus allowing us to simplify the loop body.
        for i in 1..real_max_blocks {
            for j in 0..LIMBS_PER_BLOCK {
                state[j] = state[j] ^ sliced_buffer[i * LIMBS_PER_BLOCK + j];
            }
            state = keccakf1600(state);
        }

        state
    } else {
        // We store the intermediate states in an array to avoid having a dynamic predicate
        // inside the loop, which can cause a blowup in a constrained runtime.
        let mut intermediate_states = [state; (N + BLOCK_SIZE_IN_BYTES) / BLOCK_SIZE_IN_BYTES + 1];
        for i in 1..max_blocks {
            let mut previous_state = intermediate_states[i - 1];
            for j in 0..LIMBS_PER_BLOCK {
                previous_state[j] = previous_state[j] ^ sliced_buffer[i * LIMBS_PER_BLOCK + j];
            }
            intermediate_states[i] = keccakf1600(previous_state);
        }

        // We can then take the state as of `real_max_blocks`, ignoring later permutations.
        intermediate_states[real_max_blocks - 1]
    };

    //3. sponge_squeeze
    let mut result = [0; 32];
    for i in 0..4 {
        let lane = state[i] as Field;
        let lane_le: [u8; 8] = lane.to_le_bytes();
        for j in 0..8 {
            result[8 * i + j] = lane_le[j];
        }
    }
    result
}

// Apply Keccak padding to the block_bytes array
// Append 0x01 after message, then 0x80 at end of block
// If both padding bytes collide at the same byte, combine them as 0x81
pub(crate) fn apply_keccak_padding<let BLOCK_BYTES: u32>(
    block_bytes: &mut [u8; BLOCK_BYTES],
    message_size: u32,
    real_max_blocks: u32,
) {
    let real_blocks_bytes = real_max_blocks * BLOCK_SIZE_IN_BYTES;

    block_bytes[message_size] = 0x01;

    if message_size == real_blocks_bytes - 1 {
        // Combine both padding bits: 0x01 | 0x80 = 0x81
        block_bytes[message_size] = 0x81;
    } else {
        block_bytes[real_blocks_bytes - 1] = 0x80;
    }
}

65.source:
use std::default::Default;
use std::hash::Hasher;

comptime global RATE: u32 = 3;

pub struct Poseidon2 {
    cache: [Field; 3],
    state: [Field; 4],
    cache_size: u32,
    squeeze_mode: bool, // 0 => absorb, 1 => squeeze
}

impl Poseidon2 {
    #[no_predicates]
    pub fn hash<let N: u32>(input: [Field; N], message_size: u32) -> Field {
        Poseidon2::hash_internal(input, message_size, message_size != N)
    }

    pub(crate) fn new(iv: Field) -> Poseidon2 {
        let mut result =
            Poseidon2 { cache: [0; 3], state: [0; 4], cache_size: 0, squeeze_mode: false };
        result.state[RATE] = iv;
        result
    }

    fn perform_duplex(&mut self) {
        // add the cache into sponge state
        for i in 0..RATE {
            // We effectively zero-pad the cache by only adding to the state
            // cache that is less than the specified `cache_size`
            if i < self.cache_size {
                self.state[i] += self.cache[i];
            }
        }
        self.state = crate::poseidon2_permutation(self.state, 4);
    }

    fn absorb(&mut self, input: Field) {
        assert(!self.squeeze_mode);
        if self.cache_size == RATE {
            // If we're absorbing, and the cache is full, apply the sponge permutation to compress the cache
            self.perform_duplex();
            self.cache[0] = input;
            self.cache_size = 1;
        } else {
            // If we're absorbing, and the cache is not full, add the input into the cache
            self.cache[self.cache_size] = input;
            self.cache_size += 1;
        }
    }

    fn squeeze(&mut self) -> Field {
        assert(!self.squeeze_mode);
        // If we're in absorb mode, apply sponge permutation to compress the cache.
        self.perform_duplex();
        self.squeeze_mode = true;

        // Pop one item off the top of the permutation and return it.
        self.state[0]
    }

    fn hash_internal<let N: u32>(
        input: [Field; N],
        in_len: u32,
        is_variable_length: bool,
    ) -> Field {
        let two_pow_64 = 18446744073709551616;
        let iv: Field = (in_len as Field) * two_pow_64;
        let mut sponge = Poseidon2::new(iv);
        for i in 0..input.len() {
            if i < in_len {
                sponge.absorb(input[i]);
            }
        }

        // In the case where the hash preimage is variable-length, we append `1` to the end of the input, to distinguish
        // from fixed-length hashes. (the combination of this additional field element + the hash IV ensures
        // fixed-length and variable-length hashes do not collide)
        if is_variable_length {
            sponge.absorb(1);
        }
        sponge.squeeze()
    }
}

pub struct Poseidon2Hasher {
    _state: [Field],
}

impl Hasher for Poseidon2Hasher {
    fn finish(self) -> Field {
        let iv: Field = (self._state.len() as Field) * 18446744073709551616; // iv = (self._state.len() << 64)
        let mut sponge = Poseidon2::new(iv);
        for i in 0..self._state.len() {
            sponge.absorb(self._state[i]);
        }
        sponge.squeeze()
    }

    fn write(&mut self, input: Field) {
        self._state = self._state.push_back(input);
    }
}

impl Default for Poseidon2Hasher {
    fn default() -> Self {
        Poseidon2Hasher { _state: &[] }
    }
}
